                SYSTEMTIME si = new SYSTEMTIME();
                si.CreateTime();
                p.WritePStr(_si.version_client);

                // member info
                p.Write(pi.mi.sala_numero);
                //write struct info player                                               
                p.Write(pi.mi.GetInfo());
                // User Info player
                p.WriteUInt32(pi.uid);
                p.WriteStruct(pi.ui, new UserInfo());

                // Trofel Info
                //p.WriteStruct(pi.ti_current_season, new TrofelInfo());
                p.WriteZero(78);
                // User Equip
                p.WriteStruct(pi.ue, new UserEquip());

                //// Map Statistics Normal
                //for (st_i = 0; st_i < MS_NUM_MAPS; st_i++)
                //{
                //    p.WriteStruct(pi.a_ms_normal[st_i], new MapStatistics());
                //}

                //// Map Statistics Natural
                //for (st_i = 0; st_i < MS_NUM_MAPS; st_i++)
                //{
                //    p.WriteStruct(pi.a_ms_natural[st_i], new MapStatistics());
                //}

                //// Map Statistics Grand Prix
                //for (st_i = 0; st_i < MS_NUM_MAPS; st_i++)
                //{
                //    p.WriteStruct(pi.a_ms_grand_prix[st_i], new MapStatistics());
                //}

                //// Map Statistics Normal for all seasons
                //for (int j = 0; j < 9; j++)
                //{
                //    for (st_i = 0; st_i < MS_NUM_MAPS; st_i++)        //talvez algum problema aqui!
                //    {
                //        p.WriteStruct(pi.aa_ms_normal_todas_season[j][st_i], new MapStatistics());
                //    }
                //}
                p.Write(GetMapStatistic());
                // Character Info (CharEquip)
                if (pi.ei.char_info != null)
                {
                    p.WriteStruct(pi.ei.char_info, new CharacterInfo());
                }
                else
                {
                    p.WriteZero(Marshal.SizeOf(new CharacterInfo()));
                }

                // CWriteie Info
                if (pi.ei.cad_info != null)
                {
                    p.WriteStruct(pi.ei.cad_info, new CaddieInfo());
                }
                else
                {
                    p.WriteZero(Marshal.SizeOf(new CaddieInfo()));
                }

                // Club Set Info
                p.WriteStruct(pi.ei.csi, new ClubSetInfo());

                // Mascot Info
                if (pi.ei.mascot_info != null)
                {
                    p.WriteStruct(pi.ei.mascot_info, new MascotInfo());
                }
                else
                {
                    p.WriteZero(new MascotInfo().SizeOfS());
                }

                // Adiciona o buffer de tempo do Pangya
                p.WriteStruct(si, new PangyaTime());

                // Config do Server
                p.WriteUInt16(1); // Valor padrão, 1 na primeira vez, 2 para logins subsequentes
                p.WriteStruct(pi.mi.papel_shop, pi.mi.papel_shop);
                p.WriteInt32(0); // Valor novo no JP, indicado como 0 em novas contas
                p.WriteUInt64(pi.block_flag.m_flag.ullFlag); // Flag do server para bloquear sistemas
                p.WriteUInt32(0); // Quantidade de vezes que logou
                p.WriteUInt32(_si.propriedade.ulProperty); // Propriedade do servidor
                return p;
            }
            catch (Exception e)
            {
                _smp.message_pool.push("[packet_func_gs::principal]", e);
                return p;
            }
        }

