            p.WriteInt16(sub_tipo);

            if (sub_tipo == 0x102)
                p.WriteByte((byte)option);

            else if (sub_tipo == 0x111)
            {
                p.WriteInt32(option);

                if (pi == null)
                {
                    //delete p;

                    throw new Exception("Erro PlayerInfo *pi is nullptr. packet_func::pacote095()");
                }

                p.WriteUInt64(pi.ui.pang);
            }
            return null;
        }

