        public static PangyaBinaryWriter pacote04D(List<Channel> v_element, int option = 0)
        {
            var p = new PangyaBinaryWriter();
            p.Write(new byte[] { 0x4D , 0x00, (byte)v_element.Count });
            for (var i = 0; i < v_element.Count; ++i)
            {
                var channel = v_element[i].getInfo();
                p.WriteStr(channel.name, 40);
                p.WriteInt16(channel.max_user);
                p.WriteInt16(channel.curr_user);
                p.WriteUInt32(channel.InternalGetFlag());
                p.WriteUInt32(channel.flag2);
                p.WriteUInt32(channel.max_level_allow);
                p.WriteUInt32(channel.min_level_allow);
            }
            return p;
        }

        public static PangyaBinaryWriter pacote04E(int option, int _codeErrorInfo = 0)
        {
            /* Option Values
                * 1 Sucesso
                * 2 Channel Full
                * 3 Nao encontrou canal
                * 4 Nao conseguiu pegar informções do canal
                * 6 ErrorCode Info
                */
            var p = new PangyaBinaryWriter();
            p.init_plain(0x4E);

            p.WriteByte((byte)option);

            if (_codeErrorInfo != 0)
                p.WriteInt32(_codeErrorInfo);
            return p;
        }

        public static PangyaBinaryWriter pacote044(ServerInfoEx _si, int option, PlayerInfo pi = null, int valor = 0)
        {
            var p = new PangyaBinaryWriter();

            if (option == 0 && pi == null)
                throw new Exception("Erro PlayerInfo *pi is nullptr. packet_func::pacote044()");

            p.WriteByte(0x44);

            p.WriteByte((byte)(option & 0xFF));   // Option

            if (option == 0)
                p.Write(principal(pi, _si).GetBytes);
            else if (option == 1)
                p.WriteByte(0);
            else if (option == 0xD3)
                p.WriteByte(0);
            else if (option == 0xD2)
                p.WriteInt32(valor);

            return p;
        }

        public static PangyaBinaryWriter pacote0B2(

List<MsgOffInfo> v_element,
int option = 0)
        {
            var p = new PangyaBinaryWriter();

            p.init_plain((ushort)0xB2);

            p.WriteInt32(2); // Não sei bem o que é, mas pode ser uma opção

            p.WriteInt32(option);

            p.WriteUInt32((uint)v_element.Count);

            foreach (MsgOffInfo i in v_element)
            {
                p.WriteStruct(i, new MsgOffInfo());
            }

            return p;
        }
